  import org.apache.log4j.Logger;
  import java.sql.Connection;
  import java.sql.ResultSet;
  import java.sql.SQLException;
  import java.sql.Statement; 
  import java.util.Iterator;

  import sailpoint.api.Provisioner;
  import sailpoint.api.SailPointContext;
  import sailpoint.object.Identity;
  import sailpoint.tools.GeneralException;
  import sailpoint.tools.Util;
  import sailpoint.api.ObjectUtil;
  import sailpoint.tools.Message;
  import sailpoint.object.Filter;
  import sailpoint.object.QueryOptions;
  
   import org.apache.commons.logging.Log;
  import org.apache.commons.logging.LogFactory;

  
  
  public Set updateIdentity(String dbCode,String dbDesc,String table) throws GeneralException{
		
		dbBusinessUnit = dbCode;
		dbBusinessUnitDescription = dbDesc;
		dbBuildingId = dbCode;
		dbLocationDescription = dbDesc; 
		
		QueryOptions opEmpID = new QueryOptions();
		opEmpID.setCloneResults(true);
		
    	opEmpID.add(Filter.ignoreCase(Filter.eq("ministry", ministryVal)));
		if(Util.nullSafeCaseInsensitiveEq(table, locationTable)){
			opEmpID.add( Filter.and( Filter.ignoreCase(Filter.eq(buildingId, dbBuildingId)), (Filter.or( Filter.ignoreCase(Filter.ne(locationDescription, dbLocationDescription)),Filter.isnull(locationDescription)) ) ) );
		}else{
			opEmpID.add( Filter.and( Filter.ignoreCase(Filter.eq(businessUnit, dbBusinessUnit)), (Filter.or( Filter.ignoreCase(Filter.ne(businessUnitDescription, dbBusinessUnitDescription)) ,Filter.isnull(businessUnitDescription)) ) ) );
		}
   
   
    
		Iterator itrID = context.search(Identity.class,opEmpID,"name");
		if (!Util.isEmpty(itrID)) {
			while (itrID.hasNext()) {
				if(Util.nullSafeCaseInsensitiveEq(table, locationTable)){
				  searchCountLoc++;
				}else{
				  searchCountBus++;
				}

				Object[] currentUser = (Object[]) itrID.next(); 
		 
				if(currentUser != null && currentUser[0] != null) {
					idCube =  ObjectUtil.lockIdentity(context, currentUser[0].toString());
					if(idCube!=null){
						if(Util.nullSafeCaseInsensitiveEq(table, locationTable)){
							idCube.setAttribute(locationDescription, dbLocationDescription);
						}else{
							idCube.setAttribute(businessUnitDescription, dbBusinessUnitDescription);
						}
								
						context.saveObject(idCube);
						ObjectUtil.unlockIdentity(context, idCube);

						updatedSet.add(idCube.getName());
						if(updatedSet.size()%50==0){
						  context.commitTransaction();
						}
					}
				}
			}
			context.commitTransaction();
			Util.flushIterator(itrID);
		}
    
		return updatedSet;
	}
  
  
	public Map getDetailsFromDB(String table) {
		Map dbDataMap = new HashMap();
		
		Statement stmt = null;
		ResultSet rs = null;
		try {
			conn = context.getJdbcConnection();
			if (conn != null) {
				stmt = conn.createStatement();
				String sql = "";
				if(Util.nullSafeCaseInsensitiveEq(table, locationTable)){
					sql = "select location_id as code, location_name as val from locations where location_id is not null and location_id !=''";
				}else{
					sql = "Select business_code as code, business_description as val from businessdescription where business_code is not null and business_code !=''";
				}
				rs = stmt.executeQuery(sql);

				while (rs!=null && rs.next()) {
					dbDataMap.put(rs.getString("code"), rs.getString("val"));
				}
			}
		} catch (SQLException se) {
			logger.error("Exception in reading from database: "+ se.getMessage());
			taskResult.addMessage(new Message(Message.Type.Error, "Exception: "+se.getMessage(), null));
		} catch (Exception e) {
			logger.error("Exception in reading from database: "+ e.getMessage());
			taskResult.addMessage(new Message(Message.Type.Error, "Exception: "+e.getMessage(), null));
		} finally {
			try {
				if (rs != null){rs.close();}
				if (stmt != null){stmt.close();}
				
			} catch (SQLException se2) {
				logger.error("Exception in closing database connection: "+ se2.getMessage());
				taskResult.addMessage(new Message(Message.Type.Error, "Exception: "+se2.getMessage(), null));
			}
		}
		return dbDataMap;
	}
	
	public Map getDBLocationData(){
		Map locMap = new HashMap();
		locMap = getDetailsFromDB(locationTable);
		return locMap;
	}
	
	public Map getDBBusinessData() {
		Map busMap = new HashMap();
    busMap = getDetailsFromDB(businessTable);
		return busMap;
	}
	
  
  /*
  *Rule Starts
  */
  
   Log logger = LogFactory.getLog("Ascension-Rule-Update-Amita-Identity");
   logger.debug("Ascension-Rule-Update-Amita-Identity Starting");
  
  Connection conn = null;
  
  String businessUnit = "businessUnit";
  String businessUnitDescription = "businessUnitDescription";
  String buildingId = "buildingId";
  String locationDescription = "locationDescription";
  
  String dbBusinessUnit ;
  String dbBusinessUnitDescription ;
  String dbBuildingId ;
  String dbLocationDescription ; 
  
  Identity idCube ;
  
  String locationTable = "locations";
	String businessTable = "businessdescription";
  int searchCountBus = 0;
  int searchCountLoc = 0;
  String ministryVal = "AMITA Health";
  Set errorListSet = new HashSet();
  Set<String> updatedSet = new HashSet();
  Set<String> notUpdatedSet = new HashSet();
   
	Map dataMap = new HashMap();
  Map dbMap = new HashMap();
  
  Map tempBusMap = getDBBusinessData();
  if(!Util.isEmpty(tempBusMap)){
    dbMap.put(businessTable,tempBusMap);
  }
  Map tempLocMap = getDBLocationData();
  if(!Util.isEmpty(tempLocMap)){
    dbMap.put(locationTable,tempLocMap);
  }

  
		
	for (String tableDB : dbMap.keySet()) {
		if (dbMap.get(tableDB) != null) {
			dataMap = dbMap.get(tableDB);
			for (String key : dataMap.keySet()) {
				if (Util.isNotNullOrEmpty(dataMap.get(key))) {
					try {
						updateIdentity(key, dataMap.get(key), tableDB);
					} catch (GeneralException e) {
						logger.error("Error in update user "+ e.getMessage());
						taskResult.addMessage(new Message(Message.Type.Error, "Exception: "+e.getMessage(), null));
					}
				}
			}
		}
	}
 
  
  
	taskResult.setAttribute("identitiesUpdated",updatedSet);  
  taskResult.setAttribute("identitiesNotUpdated",notUpdatedSet); 
  
  taskResult.setAttribute("misMatchCountLocation",searchCountLoc);
  taskResult.setAttribute("misMatchCountBusiness",searchCountBus); 
  
  
  logger.debug("Ascension-Rule-Update-Amita-Identity End");
  
  return ""+updatedSet;
